{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMa2RrwX4ltshKKenlQJfOc"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"QpajqlF6ML58"},"outputs":[],"source":["import os\n","import json\n","import gzip\n","import numpy as np\n","import pandas as pd\n","import joblib\n","from scipy import sparse\n","from scipy.io import mmread\n","import matplotlib.pyplot as plt\n","from PIL import Image\n","\n","\n","def run_somics_overlay(sample_dir, model_pkl, out_dir, caf_threshold=0.5):\n","\n","    def read_tsv(path):\n","        if os.path.exists(path):\n","            return pd.read_csv(path, sep=\"\\t\", header=None)\n","        if os.path.exists(path + \".gz\"):\n","            return pd.read_csv(path + \".gz\", sep=\"\\t\", header=None, compression=\"gzip\")\n","        raise FileNotFoundError(path)\n","\n","    def read_mtx(path):\n","        if os.path.exists(path):\n","            return mmread(path)\n","        if os.path.exists(path + \".gz\"):\n","            with gzip.open(path + \".gz\", \"rb\") as f:\n","                return mmread(f)\n","        raise FileNotFoundError(path)\n","\n","    def log1p_cpm(counts):\n","        c = counts.tocsc(copy=True)\n","        col_sums = np.array(c.sum(axis=0)).ravel()\n","        col_sums[col_sums == 0] = 1.0\n","        c = c.multiply(1e6 / col_sums)\n","        c = c.tocsr()\n","        c.data = np.log1p(c.data)\n","        return c\n","\n","    # ------------------------\n","    # Load expression\n","    # ------------------------\n","    mtx_dir = os.path.join(sample_dir, \"filtered_feature_bc_matrix\")\n","    counts = read_mtx(os.path.join(mtx_dir, \"matrix.mtx\")).tocsr()\n","    features = read_tsv(os.path.join(mtx_dir, \"features.tsv\"))\n","    barcodes = read_tsv(os.path.join(mtx_dir, \"barcodes.tsv\"))\n","\n","    feature_ids = features.iloc[:,0].astype(str).tolist()\n","    barcode_ids = barcodes.iloc[:,0].astype(str).tolist()\n","\n","    # ------------------------\n","    # Load spatial\n","    # ------------------------\n","    spatial_dir = os.path.join(sample_dir, \"spatial\")\n","\n","    pos_path1 = os.path.join(spatial_dir, \"tissue_positions_list.csv\")\n","    pos_path2 = os.path.join(spatial_dir, \"tissue_positions.csv\")\n","\n","    if os.path.exists(pos_path1):\n","        pos = pd.read_csv(pos_path1, header=None)\n","        pos.columns = [\"barcode\",\"in_tissue\",\"array_row\",\"array_col\",\"pxl_row\",\"pxl_col\"]\n","    else:\n","        pos = pd.read_csv(pos_path2)\n","        pos = pos.rename(columns={\n","            \"pxl_row_in_fullres\":\"pxl_row\",\n","            \"pxl_col_in_fullres\":\"pxl_col\"\n","        })\n","\n","    pos = pos[pos[\"in_tissue\"] == 1]\n","\n","    barcode_to_index = {b:i for i,b in enumerate(barcode_ids)}\n","    keep_indices = [barcode_to_index[b] for b in pos[\"barcode\"] if b in barcode_to_index]\n","\n","    counts = counts[:, keep_indices]\n","    barcodes_kept = [barcode_ids[i] for i in keep_indices]\n","\n","    counts = log1p_cpm(counts)\n","\n","    # ------------------------\n","    # Load model\n","    # ------------------------\n","    bundle = joblib.load(model_pkl)\n","    model = bundle[\"model\"]\n","    model_features = bundle[\"model_features_ordered\"]\n","\n","    vis_genes = [g.split(\".\")[0] for g in feature_ids]\n","    model_genes = [g.split(\".\")[0] for g in model_features]\n","\n","    gene_map = {}\n","    for i,g in enumerate(vis_genes):\n","        if g not in gene_map:\n","            gene_map[g] = i\n","\n","    X_cols = []\n","    for g in model_genes:\n","        if g in gene_map:\n","            X_cols.append(counts[gene_map[g],:].T)\n","        else:\n","            X_cols.append(sparse.csr_matrix((counts.shape[1],1)))\n","\n","    X = sparse.hstack(X_cols).tocsr()\n","\n","    probs = model.predict_proba(X)[:,1]\n","\n","    pos = pos[pos[\"barcode\"].isin(barcodes_kept)].copy()\n","    pos[\"pCAF\"] = pd.Series(probs, index=barcodes_kept).reindex(pos[\"barcode\"]).values\n","    pos[\"CAF_high\"] = (pos[\"pCAF\"] >= caf_threshold).astype(int)\n","\n","    os.makedirs(out_dir, exist_ok=True)\n","    pos.to_csv(os.path.join(out_dir, \"spots_predictions.csv\"), index=False)\n","\n","    # ------------------------\n","    # Overlay\n","    # ------------------------\n","    img = Image.open(os.path.join(spatial_dir, \"tissue_lowres_image.png\"))\n","\n","    with open(os.path.join(spatial_dir, \"scalefactors_json.json\")) as f:\n","        sf = json.load(f)\n","\n","    scale = sf.get(\"tissue_lowres_scalef\", 1.0)\n","\n","    x = pos[\"pxl_col\"].values * scale\n","    y = pos[\"pxl_row\"].values * scale\n","\n","    plt.figure(figsize=(7,6))\n","    plt.imshow(img)\n","    sc = plt.scatter(x, y, c=pos[\"pCAF\"], s=10, alpha=0.8, vmin=0, vmax=1)\n","    plt.axis(\"off\")\n","    plt.colorbar(sc, label=\"p(CAF-high)\")\n","    plt.savefig(os.path.join(out_dir, \"pCAF_overlay.png\"), dpi=300)\n","    plt.close()\n","\n","    return \"Done\""]}]}